"use client";

import React, { useRef } from "react";
import Link from "next/link";
import { useGSAP } from "@gsap/react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { MagneticButton } from "@/components/ui/MagneticButton";

gsap.registerPlugin(ScrollTrigger);

const CTA = () => {
  const sectionRef = useRef<HTMLDivElement>(null);

  useGSAP(() => {
    gsap.fromTo(
      ".cta-heading",
      { opacity: 0, y: 80 },
      {
        opacity: 1,
        y: 0,
        duration: 1,
        ease: "power3.out",
        scrollTrigger: {
          trigger: ".cta-heading",
          start: "top 85%",
        },
      }
    );
    gsap.fromTo(
      ".cta-btn",
      { opacity: 0, y: 30 },
      {
        opacity: 1,
        y: 0,
        duration: 0.7,
        ease: "power3.out",
        delay: 0.3,
        scrollTrigger: {
          trigger: ".cta-btn",
          start: "top 90%",
        },
      }
    );
  }, { scope: sectionRef });

  return (
    <section ref={sectionRef} className="bg-[#f2f2f2] px-5 md:px-6 py-6">
      <div
        className="max-w-[1800px] mx-auto overflow-hidden flex flex-col items-center justify-center text-center"
        style={{
          background: "#49C88B",
          borderRadius: "48px",
          padding: "120px 60px",
        }}
      >
        <h2
          className="cta-heading font-barlow-condensed text-black uppercase font-black italic leading-[0.88] mb-10"
          style={{ fontSize: "clamp(64px, 10vw, 160px)", letterSpacing: "-0.02em", maxWidth: "1000px" }}
        >
          Start a Project.<br />Then Make It All Happen.
        </h2>

        <p className="font-plus-jakarta text-black/70 text-xl leading-relaxed max-w-lg mb-12">
          Tell us what you need built. We'll scope it, price it, and get started immediately.
        </p>

        <div className="cta-btn flex flex-col sm:flex-row gap-4 items-center">
          <MagneticButton>
            <Link
              href="/contact"
              className="bg-black text-white font-plus-jakarta font-bold text-base uppercase tracking-[0.1em] px-10 py-5 rounded-full group flex items-center gap-3 hover:gap-5 transition-all duration-300"
            >
              Work with Us
              <span className="text-lg">↗</span>
            </Link>
          </MagneticButton>
          <MagneticButton>
            <Link
              href="/work"
              className="border-2 border-black text-black font-plus-jakarta font-bold text-base uppercase tracking-[0.1em] px-10 py-5 rounded-full hover:bg-black hover:text-white transition-all duration-300"
            >
              See Our Work
            </Link>
          </MagneticButton>
        </div>
      </div>
    </section>
  );
};

export default CTA;

"use client";

import React, { useRef } from "react";
import { useGSAP } from "@gsap/react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

gsap.registerPlugin(ScrollTrigger);

const features = [
  {
    number: "1",
    title: "Ship in Days.",
    body: "No lengthy retainers. No discovery phases that last forever. You describe the problem, we scope it, we build it. Most projects go live within 5–10 business days.",
  },
  {
    number: "2",
    title: "Transparent Process.",
    body: "You get full access to Notion boards, staging environments, and direct Slack communication. Zero black boxes.",
  },
  {
    number: "3",
    title: "Built for the Real World.",
    body: "We've worked with operators, founders, and lean teams. We know the difference between clever AI demos and AI that actually saves time.",
  },
];

const Features = () => {
  const sectionRef = useRef<HTMLDivElement>(null);

  useGSAP(() => {
    gsap.fromTo(
      ".feature-item",
      { opacity: 0, x: -40 },
      {
        opacity: 1,
        x: 0,
        duration: 0.7,
        ease: "power3.out",
        stagger: 0.15,
        scrollTrigger: {
          trigger: ".feature-item",
          start: "top 85%",
        },
      }
    );

    gsap.fromTo(
      ".feature-side",
      { opacity: 0, y: 60 },
      {
        opacity: 1,
        y: 0,
        duration: 0.9,
        ease: "power3.out",
        scrollTrigger: {
          trigger: ".feature-side",
          start: "top 85%",
        },
      }
    );
  }, { scope: sectionRef });

  return (
    <section ref={sectionRef} className="bg-[#f2f2f2] px-5 md:px-6 py-6">
      <div
        className="max-w-[1800px] mx-auto bg-black overflow-hidden"
        style={{ borderRadius: "48px", padding: "80px 60px" }}
      >
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
          {/* Left: big statement */}
          <div className="feature-side">
            <div className="flex items-center gap-3 mb-10">
              <span className="text-[11px] uppercase tracking-[0.25em] font-bold text-black bg-[#49C88B] px-4 py-2 rounded-full">
                Why Amalby
              </span>
            </div>
            <h2
              className="font-barlow-condensed text-white uppercase font-black italic leading-[0.88]"
              style={{ fontSize: "clamp(60px, 8vw, 130px)", letterSpacing: "-0.01em" }}
            >
              Serious.<br />
              <span style={{ WebkitTextStroke: "2px #49C88B", color: "transparent" }}>Fast.</span><br />
              No Fluff.
            </h2>

            <p className="text-white/50 font-plus-jakarta text-lg leading-relaxed mt-8 max-w-md">
              The AI space is full of hype. We're not here to sell you on the future.
              We're here to build it, for your specific business, right now.
            </p>
          </div>

          {/* Right: numbered features */}
          <div className="flex flex-col gap-0 divide-y divide-white/10 border-t border-white/10">
            {features.map((f) => (
              <div
                key={f.number}
                className="feature-item py-8 group cursor-default"
              >
                <div className="flex gap-6 items-start">
                  <span className="text-[11px] font-bold text-white/30 mt-1 font-plus-jakarta shrink-0">
                    0{f.number}
                  </span>
                  <div>
                    <h3
                      className="font-barlow-condensed text-white uppercase font-black italic leading-none mb-3"
                      style={{ fontSize: "clamp(28px, 3vw, 48px)" }}
                    >
                      {f.title}
                    </h3>
                    <p className="text-white/50 font-plus-jakarta text-[15px] leading-relaxed">
                      {f.body}
                    </p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Features;

"use client";

import React from "react";
import Link from "next/link";

const Hero = () => {
  return (
    <section className="w-full bg-[#0D0D0D] p-5 md:p-6 min-h-screen">
      {/* ── Main Hero Card ────────────────────────────────────────────── */}
      <div 
        className="relative w-full h-[calc(100vh-3rem)] max-w-[1800px] mx-auto bg-[#0A0A0A] overflow-hidden flex items-center justify-center p-8 border border-white/10"
        style={{ borderRadius: "40px" }}
      >

        {/* ── Glassmorphic Background Elements ────────────────────────── */}
        <div className="absolute inset-0 pointer-events-none">
          {/* Subtle Glow Left */}
          <div 
            className="absolute top-[20%] left-[-10%] w-[50vw] h-[50vw] rounded-full opacity-20"
            style={{ 
              background: "radial-gradient(circle, #1e1e4a 0%, transparent 70%)", 
              filter: "blur(80px)" 
            }}
          />
          {/* Subtle Glow Right */}
          <div 
            className="absolute bottom-[-10%] right-[-10%] w-[45vw] h-[45vw] rounded-full opacity-15"
            style={{ 
              background: "radial-gradient(circle, #0c2030 0%, transparent 70%)", 
              filter: "blur(90px)" 
            }}
          />
        </div>

        {/* ── Center Branding & Content ────────────────────────────────── */}
        <div className="relative z-20 w-full max-w-[1400px] flex items-center justify-center">

          {/* Left Wordmark Logo */}
          <div className="absolute left-10 top-1/2 -translate-y-1/2 hidden md:block">
            <span className="font-plus-jakarta font-bold text-white text-[1.4rem] tracking-tight opacity-100 select-none">
              amalby
            </span>
          </div>

          {/* Main Headline */}
          <h1 
            className="font-plus-jakarta text-white font-semibold text-center leading-[0.95] select-none"
            style={{ 
              fontSize: "clamp(48px, 6vw, 92px)", 
              letterSpacing: "-0.035em",
              maxWidth: "900px"
            }}
          >
            Agents for now,<br />not for later.
          </h1>
        </div>
      </div>
    </section>
  );
};

export default Hero;
